    """Convert phases to JSON-serializable format."""
    return [
        {
            "number": phase.number,
            "suffix": phase.suffix,
            "name": phase.name,
            "nodes": [
                {
                    "id": step.id,
                    "slug": step.slug,
                    "description": step.description,
                    "status": step.status,
                    "pr": step.pr,
                    "depends_on": list(step.depends_on) if step.depends_on is not None else None,
                }
                for step in phase.nodes
